class OrigonThemes {
  static const OrigonThemeData kriptoDark = OrigonThemeData(
    brand: OrigonBrand.kripto,
    mode: OrigonThemeMode.dark,
    semantic: _kriptoDarkSemantic,
  );
  static const OrigonThemeData kriptoLight = OrigonThemeData(
    brand: OrigonBrand.kripto,
    mode: OrigonThemeMode.light,
    semantic: _kriptoLightSemantic,
  );
  static const OrigonThemeData hisseDark = OrigonThemeData(
    brand: OrigonBrand.hisse,
    mode: OrigonThemeMode.dark,
    semantic: _hisseDarkSemantic,
  );
  static const OrigonThemeData hisseLight = OrigonThemeData(
    brand: OrigonBrand.hisse,
    mode: OrigonThemeMode.light,
    semantic: _hisseLightSemantic,
  );
  static const OrigonThemeData globalDark = OrigonThemeData(
    brand: OrigonBrand.global,
    mode: OrigonThemeMode.dark,
    semantic: _globalDarkSemantic,
  );
  static const OrigonThemeData globalLight = OrigonThemeData(
    brand: OrigonBrand.global,
    mode: OrigonThemeMode.light,
    semantic: _globalLightSemantic,
  );

  static OrigonThemeData resolve(OrigonBrand brand, OrigonThemeMode mode) {
    switch (brand) {
      case OrigonBrand.kripto:
        return mode == OrigonThemeMode.dark ? kriptoDark : kriptoLight;
      case OrigonBrand.hisse:
        return mode == OrigonThemeMode.dark ? hisseDark : hisseLight;
      case OrigonBrand.global:
        return mode == OrigonThemeMode.dark ? globalDark : globalLight;
    }
  }
}
